   605→    /**
   606→     * Returns {@code true} if the watermark is after the end timestamp plus the allowed lateness of
   607→     * the given window.
   608→     */
   609→    protected boolean isWindowLate(W window) {
   610→        return (windowAssigner.isEventTime()
   611→                && (cleanupTime(window) <= internalTimerService.currentWatermark()));
   612→    }
   613→
   614→    /**
   615→     * Decide if a record is currently late, based on current watermark and allowed lateness.
   616→     *
   617→     * @param element The element to check
   618→     * @return The element for which should be considered when sideoutputs
   619→     */
   620→    protected boolean isElementLate(StreamRecord<IN> element) {
   621→        return (windowAssigner.isEventTime())
   622→                && (element.getTimestamp() + allowedLateness
   623→                        <= internalTimerService.currentWatermark());
   624→    }
   625→
   626→    /**
   627→     * Registers a timer to cleanup the content of the window.
   628→     *
   629→     * @param window the window whose state to discard
   630→     */
   631→    protected void registerCleanupTimer(W window) {
   632→        long cleanupTime = cleanupTime(window);
   633→        if (cleanupTime == Long.MAX_VALUE) {
   634→            // don't set a GC timer for "end of time"
   635→            return;
   636→        }
   637→
   638→        if (windowAssigner.isEventTime()) {
   639→            triggerContext.registerEventTimeTimer(cleanupTime);
   640→        } else {
   641→            triggerContext.registerProcessingTimeTimer(cleanupTime);
   642→        }
   643→    }
   644→
   645→    /**
   646→     * Deletes the cleanup timer set for the contents of the provided window.
   647→     *
   648→     * @param window the window whose state to discard
   649→     */
   650→    protected void deleteCleanupTimer(W window) {
   651→        long cleanupTime = cleanupTime(window);
   652→        if (cleanupTime == Long.MAX_VALUE) {
   653→            // no need to clean up because we didn't set one
   654→            return;
   655→        }
   656→        if (windowAssigner.isEventTime()) {
   657→            triggerContext.deleteEventTimeTimer(cleanupTime);
   658→        } else {
   659→            triggerContext.deleteProcessingTimeTimer(cleanupTime);
   660→        }
   661→    }
   662→
   663→    /**
   664→     * Returns the cleanup time for a window, which is {@code window.maxTimestamp +
   665→     * allowedLateness}. In case this leads to a value greater than {@link Long#MAX_VALUE} then a
   666→     * cleanup time of {@link Long#MAX_VALUE} is returned.
   667→     *
   668→     * @param window the window whose cleanup time we are computing.
   669→     */
   670→    private long cleanupTime(W window) {
   671→        if (windowAssigner.isEventTime()) {
   672→            long cleanupTime = window.maxTimestamp() + allowedLateness;
   673→            return cleanupTime >= window.maxTimestamp() ? cleanupTime : Long.MAX_VALUE;
   674→        } else {
   675→            return window.maxTimestamp();
   676→        }
   677→    }
   678→
   679→    /** Returns {@code true} if the given time is the cleanup time for the given window. */
   680→    protected final boolean isCleanupTime(W window, long time) {
   681→        return time == cleanupTime(window);
   682→    }
