   863→        @Override
   864→        public <S extends MergingState<?, ?>> void mergePartitionedState(
   865→                StateDescriptor<S, ?> stateDescriptor) {
   866→            if (mergedWindows != null && mergedWindows.size() > 0) {
   867→                try {
   868→                    S rawState =
   869→                            getKeyedStateBackend()
