   873→                        @SuppressWarnings("unchecked")
   874→                        InternalMergingState<K, W, ?, ?, ?> mergingState =
   875→                                (InternalMergingState<K, W, ?, ?, ?>) rawState;
   876→                        mergingState.mergeNamespaces(window, mergedWindows);
   877→                    } else {
   878→                        throw new IllegalArgumentException(
   879→                                "The given state descriptor does not refer to a mergeable state (MergingState)");
   880→                    }
   881→                } catch (Exception e) {
   882→                    throw new RuntimeException("Error while merging state.", e);
   883→                }
   884→            }
   885→        }
   886→
   887→        @Override
   888→        public long getCurrentProcessingTime() {
   889→            return internalTimerService.currentProcessingTime();
   890→        }
   891→
   892→        @Override
   893→        public void registerProcessingTimeTimer(long time) {
   894→            internalTimerService.registerProcessingTimeTimer(window, time);
   895→        }
   896→
   897→        @Override
