   910→        }
   911→
   912→        public TriggerResult onElement(StreamRecord<IN> element) throws Exception {
   913→            return trigger.onElement(element.getValue(), element.getTimestamp(), window, this);
   914→        }
   915→
   916→        public TriggerResult onProcessingTime(long time) throws Exception {
   917→            return trigger.onProcessingTime(time, window, this);
   918→        }
