    19→package org.apache.flink.streaming.runtime.operators.windowing;
    20→
    21→import org.apache.flink.api.common.state.ListState;
    22→import org.apache.flink.api.java.tuple.Tuple2;
    23→import org.apache.flink.streaming.api.windowing.assigners.MergingWindowAssigner;
    24→import org.apache.flink.streaming.api.windowing.windows.Window;
    25→
    26→import org.slf4j.Logger;
    27→import org.slf4j.LoggerFactory;
    28→
    29→import java.util.ArrayList;
    30→import java.util.Collection;
    31→import java.util.HashMap;
    32→import java.util.List;
    33→import java.util.Map;
    34→import java.util.stream.Collectors;
    35→
    36→/**
    37→ * Utility for keeping track of merging {@link Window Windows} when using a {@link
    38→ * MergingWindowAssigner} in a {@link WindowOperator}.
    39→ *
    40→ * <p>When merging windows, we keep one of the original windows as the state window, i.e. the window
    41→ * that is used as namespace to store the window elements. Elements from the state windows of merged
    42→ * windows must be merged into this one state window. We keep a mapping from in-flight window to
    43→ * state window that can be queried using {@link #getStateWindow(Window)}.
    44→ *
    45→ * <p>A new window can be added to the set of in-flight windows using {@link #addWindow(Window,
    46→ * MergeFunction)}. This might merge other windows and the caller must react accordingly in the
    47→ * {@link MergeFunction#merge(Object, Collection, Object, Collection)} and adjust the outside view
    48→ * of windows and state.
    49→ *
    50→ * <p>Windows can be removed from the set of windows using {@link #retireWindow(Window)}.
    51→ *
    52→ * @param <W> The type of {@code Window} that this set is keeping track of.
    53→ */
    54→public class MergingWindowSet<W extends Window> {
    55→
    56→    private static final Logger LOG = LoggerFactory.getLogger(MergingWindowSet.class);
    57→
    58→    /**
    59→     * Mapping from window to the window that keeps the window state. When we are incrementally
    60→     * merging windows starting from some window we keep that starting window as the state window to
    61→     * prevent costly state juggling.
    62→     */
    63→    private final Map<W, W> mapping;
    64→
    65→    /**
    66→     * Mapping when we created the {@code MergingWindowSet}. We use this to decide whether we need
    67→     * to persist any changes to state.
    68→     */
    69→    private final Map<W, W> initialMapping;
    70→
    71→    private final ListState<Tuple2<W, W>> state;
    72→
    73→    /** Our window assigner. */
    74→    private final MergingWindowAssigner<?, W> windowAssigner;
    75→
    76→    /** Restores a {@link MergingWindowSet} from the given state. */
    77→    public MergingWindowSet(
    78→            MergingWindowAssigner<?, W> windowAssigner, ListState<Tuple2<W, W>> state)
    79→            throws Exception {
    80→        this.windowAssigner = windowAssigner;
    81→        mapping = new HashMap<>();
    82→
    83→        Iterable<Tuple2<W, W>> windowState = state.get();
    84→        if (windowState != null) {
    85→            for (Tuple2<W, W> window : windowState) {
    86→                mapping.put(window.f0, window.f1);
    87→            }
    88→        }
    89→
    90→        this.state = state;
    91→
    92→        initialMapping = new HashMap<>();
    93→        initialMapping.putAll(mapping);
    94→    }
    95→
    96→    /**
    97→     * Persist the updated mapping to the given state if the mapping changed since initialization.
    98→     */
    99→    public void persist() throws Exception {
   100→        if (!mapping.equals(initialMapping)) {
   101→            state.update(
   102→                    mapping.entrySet().stream()
   103→                            .map((w) -> new Tuple2<>(w.getKey(), w.getValue()))
   104→                            .collect(Collectors.toList()));
   105→        }
   106→    }
   107→
   108→    /**
   109→     * Returns the state window for the given in-flight {@code Window}. The state window is the
   110→     * {@code Window} in which we keep the actual state of a given in-flight window. Windows might
   111→     * expand but we keep to original state window for keeping the elements of the window to avoid
   112→     * costly state juggling.
   113→     *
   114→     * @param window The window for which to get the state window.
   115→     */
   116→    public W getStateWindow(W window) {
   117→        return mapping.get(window);
   118→    }
   119→
   120→    /**
   121→     * Removes the given window from the set of in-flight windows.
   122→     *
   123→     * @param window The {@code Window} to remove.
   124→     */
   125→    public void retireWindow(W window) {
   126→        W removed = this.mapping.remove(window);
   127→        if (removed == null) {
   128→            throw new IllegalStateException(
   129→                    "Window " + window + " is not in in-flight window set.");
   130→        }
   131→    }
   132→
   133→    /**
   134→     * Adds a new {@code Window} to the set of in-flight windows. It might happen that this triggers
   135→     * merging of previously in-flight windows. In that case, the provided {@link MergeFunction} is
   136→     * called.
   137→     *
   138→     * <p>This returns the window that is the representative of the added window after adding. This
   139→     * can either be the new window itself, if no merge occurred, or the newly merged window. Adding
   140→     * an element to a window or calling trigger functions should only happen on the returned
   141→     * representative. This way, we never have to deal with a new window that is immediately
   142→     * swallowed up by another window.
   143→     *
   144→     * <p>If the new window is merged, the {@code MergeFunction} callback arguments also don't
   145→     * contain the new window as part of the list of merged windows.
   146→     *
   147→     * @param newWindow The new {@code Window} to add.
   148→     * @param mergeFunction The callback to be invoked in case a merge occurs.
   149→     * @return The {@code Window} that new new {@code Window} ended up in. This can also be the new
   150→     *     {@code Window} itself in case no merge occurred.

