   410→        // is an AppendingState.
   411→        windowState.update(
   412→                recordsWithTimestamp.stream()
   413→                        .map(TimestampedValue::getStreamRecord)
   414→                        .collect(Collectors.toList()));
   415→    }
   416→
   417→    private void clearAllState(
   418→            W window, ListState<StreamRecord<IN>> windowState, MergingWindowSet<W> mergingWindows)
   419→            throws Exception {
   420→        windowState.clear();
   421→        triggerContext.clear();
   422→        processContext.window = window;
   423→        processContext.clear();
   424→        if (mergingWindows != null) {
   425→            mergingWindows.retireWindow(window);
   426→            mergingWindows.persist();
   427→        }
   428→    }
   429→
   430→    /**
   431→     * {@code EvictorContext} is a utility for handling {@code Evictor} invocations. It can be
   432→     * reused by setting the {@code key} and {@code window} fields. No internal state must be kept
   433→     * in the {@code EvictorContext}.
   434→     */
   435→    class EvictorContext implements Evictor.EvictorContext {
   436→
   437→        protected K key;
   438→        protected W window;
   439→
   440→        public EvictorContext(K key, W window) {
   441→            this.key = key;
   442→            this.window = window;
   443→        }
   444→
   445→        @Override
   446→        public long getCurrentProcessingTime() {
   447→            return internalTimerService.currentProcessingTime();
   448→        }
   449→
   450→        @Override
   451→        public long getCurrentWatermark() {
   452→            return internalTimerService.currentWatermark();
   453→        }
   454→
   455→        @Override
   456→        public MetricGroup getMetricGroup() {
   457→            return EvictingWindowOperator.this.getMetricGroup();
   458→        }
   459→
   460→        public K getKey() {
   461→            return key;
   462→        }
   463→
   464→        void evictBefore(Iterable<TimestampedValue<IN>> elements, int size) {
   465→            evictor.evictBefore((Iterable) elements, size, window, this);
   466→        }
   467→
   468→        void evictAfter(Iterable<TimestampedValue<IN>> elements, int size) {
   469→            evictor.evictAfter((Iterable) elements, size, window, this);
   470→        }
   471→    }
   472→
   473→    @Override
   474→    public void open() throws Exception {
   475→        super.open();
   476→
   477→        evictorContext = new EvictorContext(null, null);
   478→        evictingWindowState =
   479→                (InternalListState<K, W, StreamRecord<IN>>)
   480→                        getOrCreateKeyedState(windowSerializer, evictingWindowStateDescriptor);
   481→    }
   482→
   483→    @Override
   484→    public void close() throws Exception {
   485→        super.close();
   486→        evictorContext = null;
   487→    }
   488→
   489→    // ------------------------------------------------------------------------
   490→    // Getters for testing
   491→    // ------------------------------------------------------------------------
   492→
   493→    @VisibleForTesting
   494→    public Evictor<? super IN, ? super W> getEvictor() {
   495→        return evictor;
   496→    }
   497→
   498→    @Override
   499→    @VisibleForTesting
   500→    @SuppressWarnings("unchecked, rawtypes")
   501→    public StateDescriptor<? extends AppendingState<IN, Iterable<IN>>, ?> getStateDescriptor() {
   502→        return (StateDescriptor<? extends AppendingState<IN, Iterable<IN>>, ?>)
   503→                evictingWindowStateDescriptor;
   504→    }
