   112→    @Override
   113→    public void processElement(StreamRecord<IN> element) throws Exception {
   114→        final Collection<W> elementWindows =
   115→                windowAssigner.assignWindows(
   116→                        element.getValue(), element.getTimestamp(), windowAssignerContext);
   117→
   118→        // if element is handled by none of assigned elementWindows
   119→        boolean isSkippedElement = true;
   120→
   121→        final K key = this.<K>getKeyedStateBackend().getCurrentKey();
   122→
   123→        if (windowAssigner instanceof MergingWindowAssigner) {
   124→            MergingWindowSet<W> mergingWindows = getMergingWindowSet();
   125→
   126→            for (W window : elementWindows) {
   127→
   128→                // adding the new window might result in a merge, in that case the actualWindow
   129→                // is the merged window and we work with that. If we don't merge then
   130→                // actualWindow == window
   131→                W actualWindow =
   132→                        mergingWindows.addWindow(
   133→                                window,
   134→                                new MergingWindowSet.MergeFunction<W>() {
   135→                                    @Override
   136→                                    public void merge(
   137→                                            W mergeResult,
   138→                                            Collection<W> mergedWindows,
   139→                                            W stateWindowResult,
   140→                                            Collection<W> mergedStateWindows)
   141→                                            throws Exception {
   142→
   143→                                        if ((windowAssigner.isEventTime()
   144→                                                && mergeResult.maxTimestamp() + allowedLateness
   145→                                                        <= internalTimerService
   146→                                                                .currentWatermark())) {
   147→                                            throw new UnsupportedOperationException(
   148→                                                    "The end timestamp of an "
   149→                                                            + "event-time window cannot become earlier than the current watermark "
   150→                                                            + "by merging. Current watermark: "
   151→                                                            + internalTimerService
   152→                                                                    .currentWatermark()
   153→                                                            + " window: "
   154→                                                            + mergeResult);
   155→                                        } else if (!windowAssigner.isEventTime()
   156→                                                && mergeResult.maxTimestamp()
   157→                                                        <= internalTimerService
   158→                                                                .currentProcessingTime()) {
   159→                                            throw new UnsupportedOperationException(
   160→                                                    "The end timestamp of a "
   161→                                                            + "processing-time window cannot become earlier than the current processing time "
   162→                                                            + "by merging. Current processing time: "
   163→                                                            + internalTimerService
   164→                                                                    .currentProcessingTime()
   165→                                                            + " window: "
   166→                                                            + mergeResult);
   167→                                        }
   168→
   169→                                        triggerContext.key = key;
   170→                                        triggerContext.window = mergeResult;
   171→
   172→                                        triggerContext.onMerge(mergedWindows);
   173→
   174→                                        for (W m : mergedWindows) {
   175→                                            triggerContext.window = m;
   176→                                            triggerContext.clear();
   177→                                            deleteCleanupTimer(m);
   178→                                        }
   179→
   180→                                        // merge the merged state windows into the newly resulting
   181→                                        // state window
   182→                                        evictingWindowState.mergeNamespaces(
   183→                                                stateWindowResult, mergedStateWindows);
   184→                                    }
   185→                                });
   186→
   187→                // drop if the window is already late
   188→                if (isWindowLate(actualWindow)) {
   189→                    mergingWindows.retireWindow(actualWindow);
   190→                    continue;
   191→                }
   192→                isSkippedElement = false;
   193→
   194→                W stateWindow = mergingWindows.getStateWindow(actualWindow);
   195→                if (stateWindow == null) {
   196→                    throw new IllegalStateException(
   197→                            "Window " + window + " is not in in-flight window set.");
   198→                }
   199→
   200→                evictingWindowState.setCurrentNamespace(stateWindow);
   201→                evictingWindowState.add(element);
   202→
   203→                triggerContext.key = key;
   204→                triggerContext.window = actualWindow;
   205→                evictorContext.key = key;
   206→                evictorContext.window = actualWindow;
   207→
   208→                TriggerResult triggerResult = triggerContext.onElement(element);
   209→
   210→                if (triggerResult.isFire()) {
   211→                    Iterable<StreamRecord<IN>> contents = evictingWindowState.get();
   212→                    if (contents == null) {
   213→                        // if we have no state, there is nothing to do
   214→                        continue;
   215→                    }
   216→                    emitWindowContents(actualWindow, contents, evictingWindowState);
   217→                }
   218→
   219→                if (triggerResult.isPurge()) {
   220→                    evictingWindowState.clear();
   221→                }
   222→                registerCleanupTimer(actualWindow);
   223→            }
   224→
   225→            // need to make sure to update the merging state in state
   226→            mergingWindows.persist();
   227→        } else {
   228→            for (W window : elementWindows) {
   229→
   230→                // check if the window is already inactive
   231→                if (isWindowLate(window)) {
   232→                    continue;
   233→                }
   234→                isSkippedElement = false;
   235→
   236→                evictingWindowState.setCurrentNamespace(window);
   237→                evictingWindowState.add(element);
   238→
   239→                triggerContext.key = key;
   240→                triggerContext.window = window;
   241→                evictorContext.key = key;
   242→                evictorContext.window = window;
   243→
   244→                TriggerResult triggerResult = triggerContext.onElement(element);
   245→
   246→                if (triggerResult.isFire()) {
   247→                    Iterable<StreamRecord<IN>> contents = evictingWindowState.get();
   248→                    if (contents == null) {
   249→                        // if we have no state, there is nothing to do
   250→                        continue;
   251→                    }
   252→                    emitWindowContents(window, contents, evictingWindowState);
   253→                }
   254→
   255→                if (triggerResult.isPurge()) {
   256→                    evictingWindowState.clear();
   257→                }
   258→                registerCleanupTimer(window);
   259→            }
   260→        }
   261→
   262→        // side output input event if
   263→        // element not handled by any window
   264→        // late arriving tag has been set
   265→        // windowAssigner is event time and current timestamp + allowed lateness no less than
   266→        // element timestamp
   267→        if (isSkippedElement && isElementLate(element)) {
   268→            if (lateDataOutputTag != null) {
   269→                sideOutput(element);
   270→            } else {
   271→                this.numLateRecordsDropped.inc();
   272→            }
   273→        }
   274→    }
