   276→    @Override
   277→    public void onEventTime(InternalTimer<K, W> timer) throws Exception {
   278→
   279→        triggerContext.key = timer.getKey();
   280→        triggerContext.window = timer.getNamespace();
   281→        evictorContext.key = timer.getKey();
   282→        evictorContext.window = timer.getNamespace();
   283→
   284→        MergingWindowSet<W> mergingWindows = null;
   285→
   286→        if (windowAssigner instanceof MergingWindowAssigner) {
   287→            mergingWindows = getMergingWindowSet();
   288→            W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
   289→            if (stateWindow == null) {
   290→                // Timer firing for non-existent window, this can only happen if a
   291→                // trigger did not clean up timers. We have already cleared the merging
   292→                // window and therefore the Trigger state, however, so nothing to do.
   293→                return;
   294→            } else {
   295→                evictingWindowState.setCurrentNamespace(stateWindow);
   296→            }
   297→        } else {
   298→            evictingWindowState.setCurrentNamespace(triggerContext.window);
   299→        }
   300→
   301→        TriggerResult triggerResult = triggerContext.onEventTime(timer.getTimestamp());
   302→
   303→        if (triggerResult.isFire()) {
   304→            Iterable<StreamRecord<IN>> contents = evictingWindowState.get();
   305→            if (contents != null) {
   306→                emitWindowContents(triggerContext.window, contents, evictingWindowState);
   307→            }
   308→        }
   309→
   310→        if (triggerResult.isPurge()) {
   311→            evictingWindowState.clear();
   312→        }
   313→
   314→        if (windowAssigner.isEventTime()
   315→                && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
   316→            clearAllState(triggerContext.window, evictingWindowState, mergingWindows);
   317→        }
   318→
   319→        if (mergingWindows != null) {
   320→            // need to make sure to update the merging state in state
   321→            mergingWindows.persist();
   322→        }
   323→    }
   324→
   325→    @Override
   326→    public void onProcessingTime(InternalTimer<K, W> timer) throws Exception {
   327→        triggerContext.key = timer.getKey();
   328→        triggerContext.window = timer.getNamespace();
   329→        evictorContext.key = timer.getKey();
   330→        evictorContext.window = timer.getNamespace();
   331→
   332→        MergingWindowSet<W> mergingWindows = null;
   333→
   334→        if (windowAssigner instanceof MergingWindowAssigner) {
   335→            mergingWindows = getMergingWindowSet();
   336→            W stateWindow = mergingWindows.getStateWindow(triggerContext.window);
   337→            if (stateWindow == null) {
   338→                // Timer firing for non-existent window, this can only happen if a
   339→                // trigger did not clean up timers. We have already cleared the merging
   340→                // window and therefore the Trigger state, however, so nothing to do.
   341→                return;
   342→            } else {
   343→                evictingWindowState.setCurrentNamespace(stateWindow);
   344→            }
   345→        } else {
   346→            evictingWindowState.setCurrentNamespace(triggerContext.window);
   347→        }
   348→
   349→        TriggerResult triggerResult = triggerContext.onProcessingTime(timer.getTimestamp());
   350→
   351→        if (triggerResult.isFire()) {
   352→            Iterable<StreamRecord<IN>> contents = evictingWindowState.get();
   353→            if (contents != null) {
   354→                emitWindowContents(triggerContext.window, contents, evictingWindowState);
   355→            }
   356→        }
   357→
   358→        if (triggerResult.isPurge()) {
   359→            evictingWindowState.clear();
   360→        }
   361→
   362→        if (!windowAssigner.isEventTime()
   363→                && isCleanupTime(triggerContext.window, timer.getTimestamp())) {
   364→            clearAllState(triggerContext.window, evictingWindowState, mergingWindows);
   365→        }
   366→
   367→        if (mergingWindows != null) {
   368→            // need to make sure to update the merging state in state
   369→            mergingWindows.persist();
   370→        }
   371→    }
   372→
   373→    private void emitWindowContents(
   374→            W window, Iterable<StreamRecord<IN>> contents, ListState<StreamRecord<IN>> windowState)
   375→            throws Exception {
   376→        timestampedCollector.setAbsoluteTimestamp(window.maxTimestamp());
   377→
   378→        // Work around type system restrictions...
   379→        FluentIterable<TimestampedValue<IN>> recordsWithTimestamp =
   380→                FluentIterable.from(contents)
   381→                        .transform(
   382→                                new Function<StreamRecord<IN>, TimestampedValue<IN>>() {
   383→                                    @Override
   384→                                    public TimestampedValue<IN> apply(StreamRecord<IN> input) {
   385→                                        return TimestampedValue.from(input);
   386→                                    }
   387→                                });
   388→        evictorContext.evictBefore(recordsWithTimestamp, Iterables.size(recordsWithTimestamp));
   389→
   390→        FluentIterable<IN> projectedContents =
   391→                recordsWithTimestamp.transform(
   392→                        new Function<TimestampedValue<IN>, IN>() {
   393→                            @Override
   394→                            public IN apply(TimestampedValue<IN> input) {
   395→                                return input.getValue();
   396→                            }
   397→                        });
   398→
   399→        processContext.window = triggerContext.window;
   400→        userFunction.process(
   401→                triggerContext.key,
   402→                triggerContext.window,
   403→                processContext,
   404→                projectedContents,
   405→                timestampedCollector);
   406→        evictorContext.evictAfter(recordsWithTimestamp, Iterables.size(recordsWithTimestamp));
   407→
   408→        // work around to fix FLINK-4369, remove the evicted elements from the windowState.
   409→        // this is inefficient, but there is no other way to remove elements from ListState, which
   410→        // is an AppendingState.
   411→        windowState.update(
   412→                recordsWithTimestamp.stream()
   413→                        .map(TimestampedValue::getStreamRecord)
   414→                        .collect(Collectors.toList()));
   415→    }
   416→
   417→    private void clearAllState(
   418→            W window, ListState<StreamRecord<IN>> windowState, MergingWindowSet<W> mergingWindows)
   419→            throws Exception {
   420→        windowState.clear();
   421→        triggerContext.clear();
   422→        processContext.window = window;
   423→        processContext.clear();
   424→        if (mergingWindows != null) {
   425→            mergingWindows.retireWindow(window);
   426→            mergingWindows.persist();
   427→        }
   428→    }
