if (windowAssigner instanceof MergingWindowAssigner) {
    MergingWindowSet<W> mergingWindows = getMergingWindowSet();

    for (W window : elementWindows) {

        // adding the new window might result in a merge, in that case the actualWindow
        // is the merged window and we work with that. If we don't merge then
        // actualWindow == window
        W actualWindow = null;
        try {
            actualWindow =
                    mergingWindows.addWindow(
                            window,
                            new MergingWindowSet.MergeFunction<W>() {
                                @Override
                                public void merge(
                                        W mergeResult,
                                        Collection<W> mergedWindows,
                                        W stateWindowResult,
                                        Collection<W> mergedStateWindows)
                                        throws Exception {

                                    if ((windowAssigner.isEventTime()
                                            && mergeResult.maxTimestamp() + allowedLateness
                                                    <= internalTimerService
                                                            .currentWatermark())) {
                                        throw new UnsupportedOperationException(
                                                "The end timestamp of an "
                                                        + "event-time window cannot become earlier than the current watermark "
                                                        + "by merging. Current watermark: "
                                                        + internalTimerService
                                                                .currentWatermark()
                                                        + " window: "
                                                        + mergeResult);
                                    } else if (!windowAssigner.isEventTime()) {
                                        long currentProcessingTime =
                                                internalTimerService.currentProcessingTime();
                                        if (mergeResult.maxTimestamp()
                                                <= currentProcessingTime) {
                                            throw new UnsupportedOperationException(
                                                    "The end timestamp of a "
                                                            + "processing-time window cannot become earlier than the current processing time "
                                                            + "by merging. Current processing time: "
                                                            + currentProcessingTime
                                                            + " window: "
                                                            + mergeResult);
                                        }
                                    }

                                    triggerContext.key = key;
                                    triggerContext.window = mergeResult;

                                    triggerContext.onMerge(mergedWindows);

                                    for (W m : mergedWindows) {
                                        triggerContext.window = m;
                                        triggerContext.clear();
                                        deleteCleanupTimer(m);
                                    }

                                    // merge the merged state windows into the newly resulting
                                    // state window
                                    windowMergingState.mergeNamespaces(
                                            stateWindowResult, mergedStateWindows);
                                }
                            });
        } catch (UnsupportedOperationException e) {
            // Merging would result in a window that is too late (past watermark + allowedLateness).
            // In this case, the element cannot be added to any window and should be treated as
            // skipped/late. Continue to the next window assignment.
            continue;
        }

        // drop if the window is already late
        if (isWindowLate(actualWindow)) {
            mergingWindows.retireWindow(actualWindow);
            continue;
        }
        isSkippedElement = false;

        W stateWindow = mergingWindows.getStateWindow(actualWindow);
        if (stateWindow == null) {
            throw new IllegalStateException(
                    "Window " + window + " is not in in-flight window set.");
        }

        windowState.setCurrentNamespace(stateWindow);
        windowState.add(element.getValue());

        triggerContext.key = key;
        triggerContext.window = actualWindow;

        TriggerResult triggerResult = triggerContext.onElement(element);

        if (triggerResult.isFire()) {
            ACC contents = windowState.get();
            if (contents != null) {
                emitWindowContents(actualWindow, contents);
            }
        }

        if (triggerResult.isPurge()) {
            windowState.clear();
        }
        registerCleanupTimer(actualWindow);
    }

    // need to make sure to update the merging state in state
    mergingWindows.persist();
} else {
    for (W window : elementWindows) {

        // drop if the window is already late
