    void testLateElementMergingSessionWindowsSideOutput() throws Exception {
        // Test for late element side output with merging/session windows
        // Bug: When an element arrives late and could extend a session window,
        // it should be side-output as a late element if all windows it's assigned to are late
        final int gapSize = 3;
        final long lateness = 0;

        ReducingStateDescriptor<Tuple2<String, Integer>> stateDesc =
                new ReducingStateDescriptor<>(
                        "window-contents",
                        new SumReducer(),
                        STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

        WindowOperatorFactory<
                        String,
                        Tuple2<String, Integer>,
                        Tuple2<String, Integer>,
                        Tuple3<String, Long, Long>,
                        TimeWindow>
                operator =
                        new WindowOperatorFactory<>(
                                EventTimeSessionWindows.withGap(Duration.ofSeconds(gapSize)),
                                new TimeWindow.Serializer(),
                                new TupleKeySelector(),
                                BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                        new SerializerConfigImpl()),
                                stateDesc,
                                new InternalSingleValueWindowFunction<>(
                                        new ReducedSessionWindowFunction()),
                                EventTimeTrigger.create(),
                                lateness,
                                lateOutputTag);

        OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
                testHarness = createTestHarness(operator);

        testHarness.open();

        ConcurrentLinkedQueue<Object> expected = new ConcurrentLinkedQueue<>();
        ConcurrentLinkedQueue<Object> sideExpected = new ConcurrentLinkedQueue<>();

        // Create initial session window
        testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 1000));
        testHarness.processWatermark(new Watermark(1999));
        expected.add(new Watermark(1999));

        // Extend session window
        testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 2000));
        testHarness.processWatermark(new Watermark(4998));
        expected.add(new Watermark(4998));

        // Advance watermark past window maxTimestamp but before cleanup (with allowedLateness=0)
        // Window [1000, 5000] is now late (cleanup time = 5000 + 0 = 5000)
        testHarness.processWatermark(new Watermark(5001));
        expected.add(new Watermark(5001));

        // Element arriving late that could theoretically merge with the session window
        // but the window is already late, so it should be side-output
        testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 1500));
        sideExpected.add(new StreamRecord<>(new Tuple2<>("key1", 1), 1500));

        ConcurrentLinkedQueue<Object> actual = testHarness.getOutput();
        ConcurrentLinkedQueue<StreamRecord<Tuple2<String, Integer>>> sideActual =
                testHarness.getSideOutput(lateOutputTag);

        TestHarnessUtil.assertOutputEqualsSorted(
                "Output was not correct.", expected, actual, new Tuple2ResultSortComparator());
        TestHarnessUtil.assertOutputEqualsSorted(
                "SideOutput was not correct.",
                sideExpected,
                (Iterable) sideActual,
                new Tuple2ResultSortComparator());

        testHarness.close();
    }
}

